// .catch() en cadena de promesas
async function cargarDatos() {
  const datos = await fetch('https://jsonplaceholder.typicode.com/posts/1')
    .then(res => {
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return res.json();
    })
    .catch(error => {
      console.error('Falló la carga:', error.message);
      return null; // valor de fallback
    });

  if (datos) console.log('Título:', datos.title);
  else console.log('Usando datos por defecto');
}

cargarDatos();

// try/catch con await — forma más legible
async function cargarUsuario(id) {
  try {
    const res = await fetch(`https://jsonplaceholder.typicode.com/users/${id}`);
    if (!res.ok) throw new Error(`No encontrado: ${res.status}`);
    const usuario = await res.json();
    console.log('Usuario:', usuario.name);
    return usuario;
  } catch (error) {
    console.error('Error al cargar usuario:', error.message);
    return { nombre: 'Anónimo', error: true }; // fallback
  }
}

await cargarUsuario(1);   // OK
await cargarUsuario(999); // retorna fallback

// Promise.allSettled — tolera fallos parciales
async function cargarTodo() {
  const [posts, usuarios] = await Promise.allSettled([
    fetch('https://jsonplaceholder.typicode.com/posts').then(r => r.json()),
    fetch('https://jsonplaceholder.typicode.com/RUTA_INVALIDA').then(r => {
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      return r.json();
    })
  ]);

  const postsData = posts.status === 'fulfilled' ? posts.value : [];
  const usuariosData = usuarios.status === 'fulfilled' ? usuarios.value : [];

  console.log(`${postsData.length} posts, ${usuariosData.length} usuarios`);
}

cargarTodo();

