function operacionRiesgosa() {
  return Promise.reject(new Error('Conexión rechazada'));
}

let errorCapturado;

await operacionRiesgosa()
  .catch(error => {
    errorCapturado = error.message;
  });

async function intentar(fn) {
  try {
    const valor = await fn();
    return { ok: true, valor };
  } catch (error) {
    return { ok: false, error: error.message };
  }
}

const exitoso = await intentar(() => Promise.resolve(42));
const fallido = await intentar(() => Promise.reject(new Error('algo falló')));

const promesas = [
  Promise.resolve('datos de usuarios'),
  Promise.reject(new Error('timeout de red')),
  Promise.resolve('datos de productos')
];

const resultados = await Promise.allSettled(promesas);

const exitosos = resultados
  .filter(r => r.status === 'fulfilled')
  .map(r => r.value);

const fallidos = resultados
  .filter(r => r.status === 'rejected')
  .map(r => r.reason.message);
